  ('judicial-8cba2e09-moex-00042', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-112-696aa37c', 'sub-judicial-8cba2e09-03', NULL, 'essay', '網路霸凌事件層出不窮，最近調查發現近半數（47.0%）青少年曾經涉入
網路霸凌事件，國中三年級的 A女在諮商中表示在網路中被班上強悍的
B 女霸凌，甚至要大家「取消掉與她的好友關係」、「讓她一個朋友都沒
有」、「一起孤立她，別跟她講話」，甚至洩漏她的個資，這些網路的霸凌
訊息無情的襲擊A女，甚至使其有輕生的念頭。身為觀護人的你請提出
常見的網路霸凌成因、行為、受害者身心影響與對此案件的處遇策略。
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:10+00:00", "source_pdf_sha1": "74bd2dd97b1e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "111", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "諮商與輔導", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL),
  ('judicial-8cba2e09-moex-00043', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-112-696aa37c', 'sub-judicial-8cba2e09-03', NULL, 'essay', 'Corey 將團體諮商歷程分為那幾個階段？請分別說明各個階段的主要內
涵，並以青少年霸凌防治團體治療計畫（六次團體）為例，列出名稱、
輔導重點及各個階段可使用的諮商技巧。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:10+00:00", "source_pdf_sha1": "74bd2dd97b1e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "111", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "諮商與輔導", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL),
  ('judicial-8cba2e09-moex-00044', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-111-359207d9', 'sub-judicial-8cba2e09-05', NULL, 'single_choice', '黃先生回到母校，看見校長室牆上掛滿匾額，下列那一個題辭不適合出現？', '["時雨春風", "澤被三臺", "絃歌盈耳", "功著杏林"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL),
  ('judicial-8cba2e09-moex-00045', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-111-359207d9', 'sub-judicial-8cba2e09-05', NULL, 'single_choice', '「愛，是人類生命存在的心靈經驗之一，只有真切地面對自己以及所愛之人內在活生 生的心靈，才能照見彼此不能相愛的障礙而加以克服。然而，他們卻遺忘了自己的 存在，只是不斷地追逐著各種外在的知識，以為這樣就能幸福快樂。」 下列敘述何者最貼近本文的旨趣？', '["知識的追逐讓人們忘了如何相愛", "體認自身之存在為追逐知識之本", "人經常忘記照見自己而產生了相愛的障礙", "相愛的根本在於面對彼此的內心而非知識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL),
  ('judicial-8cba2e09-moex-00046', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-111-359207d9', 'sub-judicial-8cba2e09-05', NULL, 'single_choice', '「美是一種生命整體存在感的湧現。當此際必然是物我兩忘，情景交融，渾成一片， 而容不下絲毫的分辨與思維。當天邊飛過一抹彩霞，你只合目瞪口呆；連一句『好 美啊』的呢喃，都已是心靈對此境的意識與抽離，也早已構成對美的留戀與破壞。」 根據上文，最符合美的感受是：', '["盡在不言中", "物我保持距離", "感官與意識的交融", "生命主體的思維湧現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL),
  ('judicial-8cba2e09-moex-00047', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-111-359207d9', 'sub-judicial-8cba2e09-05', NULL, 'single_choice', '「大多數的商業圖表都是披薩，餡料不多以免消化不良，它能在短時間內提供資訊， 用不著太多文字說明。客戶資料蒐集差不多了，就畫個條狀圖。計畫又訂出新的期 限，就畫個時程圖。但有些會議需要很多說明，例如剛併購一家公司，要向高層主 管解說營運策略如何調整，這時，披薩無法滿足胃口，要端出全套酒席，展示精細 的圖表。這種圖表能醞釀創意，引發大家交換意見，進而解決問題。」 下列敘述，最符合上文觀點的是：', '["披薩式圖表適用於基層會議，酒席式圖表適用於主管會議", "披薩式圖表適用於宣達要點，酒席式圖表適用於探討細節", "披薩式與酒席式圖表雖然各有功能，但皆應儘量少用文字", "披薩式與酒席式圖表雖然繁簡不一，但皆為引發充分討論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL),
  ('judicial-8cba2e09-moex-00048', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-111-359207d9', 'sub-judicial-8cba2e09-05', NULL, 'single_choice', '「有一座龐大的旅館，設備陳舊，管理鬆懈，營業額一落千丈。旅館的所有人聘請一 位專家來從事革新和整頓。三個月後，專家對旅館的現況有了透徹的了解，提出一 份詳細的計畫，主張把房子拆掉重新建造大樓，現有工作人員一律遣散，重新招考 訓練。旅館所有人無法接受這樣的計畫，聘請另一位專家來擔任經理。這位專家在 視察旅館的業務之後，下令換裝所有房間的自來水龍頭。新的龍頭，式樣美觀，操 作方便，絕不漏水，旅客在半夜再也聽不到滴漏之聲，可以安享一夜好睡了。就這 樣，新任經理從小處著手，積小為大，終於使旅館的作風煥然一新。旅客們發現， 這家旅館的房子雖然陳舊，但是堅固；式樣雖然古老，但是引人。於是近者悅，遠 者來。」 根據上文，旅館終能近悅遠來，其主要關鍵在於管理者：', '["不愛虛名，惟儉是尚", "前事不忘，後事之師", "圖難於其易，為大於其細", "毀譽無動於衷，榮辱在所不計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL),
  ('judicial-8cba2e09-moex-00049', 'judicial-8cba2e09', 'judicial-8cba2e09-moex-111-359207d9', 'sub-judicial-8cba2e09-05', NULL, 'single_choice', '「有些公司誤以為科技能取代人力經驗所累積的技能與判斷力。資深的航太工程師 因公司進行人事精簡，在勸退聲中離開崗位。但公司為了延續重要工作，又得重新 僱用這些離職的工程師。有些看似『可有可無』的中階主管去職後，公司才了解到 他們所經手的是關鍵性工作的相關知識，公司所損失的絕非那幾個正式職稱而已。」 下列選項，最符合上文旨意的是：', '["科技能創造知識價值卻無法取代勞力工作", "公司核心知識不宜因人事更迭而中斷傳承", "精簡人事成本必造成公司動盪缺乏向心力", "公司的人事規劃不可忽略中階主管的重要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:11+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "102", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "心理輔導員"}'::jsonb, NULL)
